output.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?gold ?goldLabel ?silver ?silverLabel ?bronze ?bronzeLabel WHERE {
  wd:Q5067018 wdt:P265 ?gold .
  wd:Q5067018 wdt:P264 ?silver .
  wd:Q5067018 wdt:P263 ?bronze .
  OPTIONAL {
    ?gold rdfs:label ?goldLabel
    FILTER(lang(?goldLabel) = "en")
  }
  .
  OPTIONAL {
    ?silver rdfs:label ?silverLabel
    FILTER(lang(?silverLabel) = "en")
  }
  .
  OPTIONAL {
    ?bronze rdfs:label ?bronzeLabel
    FILTER(lang(?bronzeLabel) = "en")
  }
  .
}

args.sparql:
SELECT ?athlete ?athleteName ?medal WHERE {
  wd:Q2150132 wdt:P977 ?event.
  ?event rdfs:label ?eventLabel.
  FILTER (lang(?eventLabel) = "en")
  FILTER (CONTAINS(LCASE(?eventLabel), "figure skating"))
  FILTER (CONTAINS(LCASE(?eventLabel), "men"))
  {
    ?event wdt:P265 ?athlete.
    BIND("Gold" AS ?medal)
  }
  UNION
  {
    ?event wdt:P264 ?athlete.
    BIND("Silver" AS ?medal)
  }
  UNION
  {
    ?event wdt:P263 ?athlete.
    BIND("Bronze" AS ?medal)
  }
  ?athlete rdfs:label ?athleteName.
  FILTER (lang(?athleteName) = "en")
}
